                    </div>
                ) : posts.length === 0 ? (
                    <div className="mgmt-empty">
                        <BookOpen size={40} strokeWidth={1} />
                        <p>No resources found</p>
                    </div>
                ) : (
                    <div className="mgmt-table-wrapper">
