                                                    <BookOpen size={14} strokeWidth={1.8} />
                                                </div>
                                                <div>
                                                    <p className="job-title">{post.title}</p>
                                                    <p className="job-company">{truncate(post.content, 50)}</p>
                                                </div>
                                            </div>
                                        </td>
                                        <td>
                                            <span className="category-badge">{post.category}</span>
                                        </td>
                                        <td>
                                            {post.user ? (
